// commonTest
class ProductRepositoryTest {
    private val fakeApi = FakeApiClient()
    private val repo = ProductRepositoryImpl(fakeApi)

    @Test
    fun getProducts_returnsProducts() = runTest {
        fakeApi.setProducts(listOf(testProduct))
        val result = repo.getProducts()
        assertEquals(1, result.size)
        assertEquals('Test Product', result.first().name)
    }
}

